// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  // Helper function to get weather emoji/icon based on condition
  const getWeatherIcon = (condition: string): string => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloudy') || conditionLower.includes('cloud')) return '☁️';
    if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('snowy') || conditionLower.includes('snow')) return '❄️';
    if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
    if (conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
    return '🌤️'; // Default partly cloudy
  };

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with city name */}
        <Box>
          <Heading level={1} color="var(--ggui-color-onSurface)">{props.city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Weather Forecast</Text>
        </Box>

        {/* Current Weather Card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* Weather Icon and Condition */}
            <Row gap="var(--ggui-spacing-4)" align="center">
              <Box>
                <Text size="4xl" style={{ lineHeight: '1' }}>{getWeatherIcon(props.condition)}</Text>
              </Box>
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Condition</Text>
                <Text variant="bodyLarge" color="var(--ggui-color-onSurface)" weight="semibold">{props.condition}</Text>
              </Stack>
            </Row>

            {/* Temperature Display */}
            <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
              <Stack align="center">
                <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)" style={{ lineHeight: '1' }}>
                  {props.temperature}°{props.unit}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-primary-700)">Current Temperature</Text>
              </Stack>
            </Box>

            {/* Humidity and Wind Speed */}
            <Row gap="var(--ggui-spacing-4)" align="stretch">
              {/* Humidity */}
              <Box flex="1" padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                <Stack gap="var(--ggui-spacing-2)" align="center">
                  <Text size="2xl" style={{ lineHeight: '1' }}>💧</Text>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                  <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
                </Stack>
              </Box>

              {/* Wind Speed */}
              <Box flex="1" padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                <Stack gap="var(--ggui-spacing-2)" align="center">
                  <Text size="2xl" style={{ lineHeight: '1' }}>💨</Text>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                  <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} km/h</Text>
                </Stack>
              </Box>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        {props.forecast && props.forecast.length > 0 && (
          <Card shadow="md" padding="var(--ggui-spacing-4)" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
              <Row gap="var(--ggui-spacing-3)" align="stretch" wrap={true} justify="start">
                {props.forecast.map((day, index) => (
                  <Card
                    key={index}
                    padding="var(--ggui-spacing-3)"
                    background="var(--ggui-color-surfaceVariant)"
                    border={false}
                    shadow="sm"
                    radius="md"
                    style={{ flex: '1 1 calc(20% - var(--ggui-spacing-3))', minWidth: '100px' }}
                  >
                    <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                      {/* Day name */}
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" align="center">
                        {day.day || `Day ${index + 1}`}
                      </Text>
                      {/* Weather icon */}
                      <Text size="2xl" style={{ lineHeight: '1' }}>
                        {day.icon ? day.icon : getWeatherIcon('cloudy')}
                      </Text>
                      {/* High/Low temps */}
                      {(day.high !== undefined || day.low !== undefined) && (
                        <Stack gap="var(--ggui-spacing-1)" align="center">
                          {day.high !== undefined && (
                            <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface)" align="center">
                              {day.high}°
                            </Text>
                          )}
                          {day.low !== undefined && (
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" align="center">
                              {day.low}°
                            </Text>
                          )}
                        </Stack>
                      )}
                    </Stack>
                  </Card>
                ))}
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

