export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // State
  const [tasks, setTasks] = useState(props.tasks);
  const [showAddForm, setShowAddForm] = useState<{ [key: string]: boolean }>({});
  const [newTaskTitle, setNewTaskTitle] = useState<{ [key: string]: string }>({});
  const [newTaskPriority, setNewTaskPriority] = useState<{ [key: string]: string }>({});
  const [newTaskAssignee, setNewTaskAssignee] = useState<{ [key: string]: string }>({});
  const [newTaskDueDate, setNewTaskDueDate] = useState<{ [key: string]: string }>({});

  // Sync with props changes
  useEffect(() => {
    setTasks(props.tasks);
  }, [props.tasks]);

  // Handle real-time updates from stream
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'delete' && task?.id) {
        setTasks((prev) => prev.filter((t) => t.id !== task.id));
      } else if (task?.id) {
        setTasks((prev) => {
          const existing = prev.findIndex((t) => t.id === task.id);
          if (existing >= 0) {
            const updated = [...prev];
            updated[existing] = { ...updated[existing], ...task };
            return updated;
          }
          return [...prev, task];
        });
      }
    }
  }, [taskChanged.latest]);

  // Get tasks for a column
  const getTasksForColumn = useCallback(
    (columnId?: string) => tasks.filter((t) => t.column === columnId),
    [tasks]
  );

  // Summary stats
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  // Handle task movement
  const handleMoveTask = (taskId: string, newColumn: string) => {
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t))
    );
  };

  // Handle task edit
  // Handle task edit
  const handleEditTask = (taskId: string, title: string) => {
    taskUpdate({ action: 'edit', taskId, data: { title } });
    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, title } : t))
    );
  };

  // Handle new task creation
  // Handle new task creation
  const handleAddTask = (columnId?: string) => {
    const title = newTaskTitle[columnId || '']?.trim();
    if (!title) return;

    const taskId = `task-${Date.now()}`;
    const newTask = {
      id: taskId,
      title,
      priority: (newTaskPriority[columnId || ''] || 'low') as 'low' | 'medium' | 'high',
      assignee: newTaskAssignee[columnId || ''] || undefined,
      dueDate: newTaskDueDate[columnId || ''] || undefined,
      column: columnId,
    };

    taskUpdate({ action: 'create', taskId, data: { column: columnId || 'todo', title, priority: newTask.priority, assignee: newTask.assignee, dueDate: newTask.dueDate } });
    setTasks((prev) => [...prev, newTask]);
    setNewTaskTitle((prev) => ({ ...prev, [columnId || '']: '' }));
    setNewTaskPriority((prev) => ({ ...prev, [columnId || '']: 'low' }));
    setNewTaskAssignee((prev) => ({ ...prev, [columnId || '']: '' }));
    setNewTaskDueDate((prev) => ({ ...prev, [columnId || '']: '' }));
    setShowAddForm((prev) => ({ ...prev, [columnId || '']: false }));
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Box
          padding="var(--ggui-spacing-4)"
          background="var(--ggui-color-primary-50)"
          borderRadius="var(--ggui-shape-radius-lg)"
        >
          <Row gap="var(--ggui-spacing-4)" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Text variant="label" color="var(--ggui-color-primary-700)">
                Total Tasks
              </Text>
              <Heading level={3} color="var(--ggui-color-primary-900)">
                {totalTasks}
              </Heading>
            </Stack>
            <Divider orientation="vertical" margin="0" />
            <Stack gap="var(--ggui-spacing-1)">
              <Text variant="label" color="var(--ggui-color-success-700)">
                Completed
              </Text>
              <Heading level={3} color="var(--ggui-color-success-900)">
                {completedTasks}
              </Heading>
            </Stack>
            <Spacer size="flex" />
            <Progress
              value={totalTasks > 0 ? completedTasks : 0}
              max={totalTasks || 1}
              variant="success"
              size="md"
              showLabel
            />
          </Row>
        </Box>

        {/* Kanban Columns */}
        <Row gap="var(--ggui-spacing-4)" align="start">
          {props.columns.map((column) => {
            const columnTasks = getTasksForColumn(column.id);
            const columnKey = column.id || '';

            return (
              <Stack gap="var(--ggui-spacing-3)" key={column.id}>
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Column Header */}
                  <Box
                    padding="var(--ggui-spacing-3)"
                    background="var(--ggui-color-surfaceVariant)"
                    borderRadius="var(--ggui-shape-radius-md)"
                  >
                    <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                      <Stack gap="var(--ggui-spacing-1)">
                        <Heading level={4} color="var(--ggui-color-onSurface)" aria-label={`${column.name} column`}>
                          {column.name}
                        </Heading>
                      </Stack>
                      <Badge variant="default" size="sm">
                        {columnTasks.length}
                      </Badge>
                    </Row>
                  </Box>

                  {/* Task Cards */}
                  {columnTasks.length > 0 ? (
                    columnTasks.map((task) => (
                      <TaskCard
                        key={task.id}
                        task={task}
