                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority[columnKey] || 'low'}
                          onChange={(val) =>
                            setNewTaskPriority((prev) => ({
                              ...prev,
                              [columnKey]: val,
                            }))
                          }
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                        />
                        <Input
                          label="Assignee (optional)"
