// Helper to get color for element category
function getCategoryColor(category?: string): string {
  const categoryColors: Record<string, string> = {
    'nonmetal': 'var(--ggui-color-primary-100)',
    'noble-gas': 'var(--ggui-color-success-100)',
    'halogen': 'var(--ggui-color-warning-100)',
    'alkali-metal': 'var(--ggui-color-error-100)',
    'alkaline-earth-metal': 'var(--ggui-color-info-100)',
    'transition-metal': 'var(--ggui-color-primary-50)',
    'post-transition-metal': 'var(--ggui-color-primary-200)',
    'semimetal': 'var(--ggui-color-warning-50)',
    'lanthanide': 'var(--ggui-color-info-50)',
    'actinide': 'var(--ggui-color-error-50)',
  };
  return categoryColors[category?.toLowerCase() || ''] || 'var(--ggui-color-surfaceVariant)';
}

// Helper to get text color based on category
function getCategoryTextColor(category?: string): string {
  const darkCategories = ['alkali-metal', 'alkaline-earth-metal', 'transition-metal', 'actinide'];
  return darkCategories.includes(category?.toLowerCase() || '') ? 'var(--ggui-color-onSurface)' : 'var(--ggui-color-onSurfaceVariant)';
}

