export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // Local state for messages and input
  const [allMessages, setAllMessages] = useState(props.messages);
  const [inputValue, setInputValue] = useState('');
  const [typingIndicator, setTypingIndicator] = useState<{ sender: string } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when messages arrive
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages]);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest]);
    }
  }, [message.latest]);

  // Handle typing indicator
  useEffect(() => {
    if (typing.latest?.active && typing.latest?.sender) {
      setTypingIndicator({ sender: typing.latest.sender });
    } else {
      setTypingIndicator(null);
    }
  }, [typing.latest]);

  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const now = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp: now });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)" direction="vertical" style={{ height: '100vh' }}>
        {/* Header */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center">
            <Stack direction="horizontal" gap="var(--ggui-spacing-3)" align="center">
              <Heading level={3}>{props.title}</Heading>
              <Badge variant="primary">{props.participantCount} participants</Badge>
            </Stack>
            {typingIndicator && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" aria-live="polite" aria-atomic="true">
                {typingIndicator.sender} is typing...
              </Text>
            )}
          </Row>
        </Card>

         {/* Messages */}
         <div role="region" aria-label="Chat messages">
           <Card
             padding="var(--ggui-spacing-4)"
             shadow="md"
             style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column' }}
           >
             <Stack gap="var(--ggui-spacing-3)" direction="vertical">
               {allMessages.length === 0 ? (
                 <Text color="var(--ggui-color-onSurfaceVariant)" align="center">
                   No messages yet
                 </Text>
               ) : (
                 allMessages.map((msg, idx) => {
                   const isOwnMessage = msg.sender === props.currentUser;
                   return (
                     <MessageBubble
                       key={idx}
                       sender={msg.sender || 'Unknown'}
                       text={msg.text || ''}
                       timestamp={msg.timestamp || ''}
                       isOwnMessage={isOwnMessage}
                     />
                   );
                 })
               )}
               <div ref={messagesEndRef} />
             </Stack>
           </Card>
         </div>

        {/* Input */}
        <Row gap="var(--ggui-spacing-2)" align="end">
          <Input
            label="Message"
            placeholder="Type a message..."
            value={inputValue}
            onChange={setInputValue}
            onKeyDown={handleKeyDown}
            style={{ flex: 1 }}
          />
           <Button
             variant="primary"
             onClick={handleSendMessage}
             disabled={!inputValue.trim()}
             aria-disabled={!inputValue.trim()}
           >
             Send
           </Button>
        </Row>
      </Stack>
    </Container>
  );
}

