            </Text>
          </Stack>
          <Badge
            variant={
              currentMarketStatus === 'open'
                ? 'success'
                : currentMarketStatus === 'pre-market' || currentMarketStatus === 'after-hours'
                ? 'warning'
                : 'error'
            }
            aria-label={`Market status: ${statusLabel}`}
          >
            {statusLabel}
