// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

const TOTAL_STEPS = 5;

const isValidEmail = (email: string): boolean => {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<number>(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touchedName, setTouchedName] = useState<boolean>(false);
  const [touchedEmail, setTouchedEmail] = useState<boolean>(false);
  const [attemptedNext, setAttemptedNext] = useState<boolean>(false);

  const nameError = useMemo(() => {
    if (!name.trim()) return 'Name is required.';
    return '';
  }, [name]);

  const emailError = useMemo(() => {
    if (!email.trim()) return 'Email is required.';
    if (!isValidEmail(email.trim())) return 'Please enter a valid email address.';
    return '';
  }, [email]);

  const satisfactionError = useMemo(() => {
    if (satisfaction < 1 || satisfaction > 5) return 'Please select a satisfaction rating.';
    return '';
  }, [satisfaction]);

  const canProceed = useMemo(() => {
    if (step === 1) return !nameError && !emailError;
    if (step === 2) return !satisfactionError;
    if (step === 3) return true;
    if (step === 4) return comments.length <= 500;
    if (step === 5) return true;
    return false;
  }, [step, nameError, emailError, satisfactionError, comments.length]);

  const progressValue = useMemo(() => (step / TOTAL_STEPS) * 100, [step]);

  const handleFeatureToggle = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const handleNext = useCallback(() => {
    setAttemptedNext(true);
    if (!canProceed) return;
    setStep((prev) => Math.min(TOTAL_STEPS, prev + 1));
    setAttemptedNext(false);
  }, [canProceed]);

  const handleBack = useCallback(() => {
    setStep((prev) => Math.max(1, prev - 1));
    setAttemptedNext(false);
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      features,
      comments: comments.trim(),
    });
  }, [submit, name, email, satisfaction, features, comments]);

  const satisfactionOptions = useMemo(() => {
    const fallbackLabels = ['1', '2', '3', '4', '5'];
    const source = props.satisfactionLabels && props.satisfactionLabels.length > 0 ? props.satisfactionLabels : fallbackLabels;
    return [1, 2, 3, 4, 5].map((value) => ({
      value: String(value),
      label: source[value - 1] || `Rating ${value}`,
    }));
  }, [props.satisfactionLabels]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" border radius="lg">
        <Stack gap="var(--ggui-spacing-5)">
          <Stack gap="var(--ggui-spacing-2)">
            <Row justify="between" align="center">
              <Heading level={3}>Multi-Step Survey</Heading>
              <Badge variant="primary">Step {step} of {TOTAL_STEPS}</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" variant="default" />
          </Stack>

          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Your Information</Heading>
              <Input
                label="Name"
                value={name}
                onChange={(value) => {
                  setName(value);
                  if (!touchedName) setTouchedName(true);
                }}
                required
                placeholder="Enter your name"
                error={(touchedName || attemptedNext) ? nameError : ''}
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={(value) => {
                  setEmail(value);
                  if (!touchedEmail) setTouchedEmail(true);
                }}
                required
                placeholder="you@example.com"
                error={(touchedEmail || attemptedNext) ? emailError : ''}
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you?"
                value={satisfaction ? String(satisfaction) : ''}
                onChange={(value) => setSatisfaction(Number(value))}
                options={satisfactionOptions}
                direction="vertical"
                error={attemptedNext ? satisfactionError : ''}
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Feature Interests</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">Select all that interest you.</Text>
              <Stack gap="var(--ggui-spacing-2)">
                {(props.featureOptions || []).length === 0 && (
                  <Alert variant="info" title="No features available">There are currently no feature options to choose from.</Alert>
                )}
                {(props.featureOptions || []).map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={(checked) => handleFeatureToggle(feature, checked)}
                  />
                ))}
              </Stack>
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Additional Comments</Heading>
              <TextArea
                label="Comments (optional)"
                value={comments}
                onChange={(value) => setComments(value.slice(0, 500))}
                rows={6}
                maxLength={500}
                showCount
                helperText="Share any additional thoughts."
              />
            </Stack>
          )}

          {step === 5 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Review Your Answers</Heading>
              <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between"><Text weight="medium">Name</Text><Text>{name || '—'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Row justify="between"><Text weight="medium">Email</Text><Text>{email || '—'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Row justify="between"><Text weight="medium">Satisfaction</Text><Text>{satisfaction > 0 ? `${satisfaction} - ${satisfactionOptions[satisfaction - 1]?.label || ''}` : '—'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text weight="medium">Feature Interests</Text>
                    <Text color="var(--ggui-color-onSurfaceVariant)">{features.length > 0 ? features.join(', ') : 'None selected'}</Text>
                  </Stack>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text weight="medium">Comments</Text>
                    <Text color="var(--ggui-color-onSurfaceVariant)">{comments.trim() ? comments : 'No comments provided'}</Text>
                  </Stack>
                </Stack>
              </Card>
            </Stack>
          )}

          <Divider margin="var(--ggui-spacing-1)" />

          <Row justify="between" align="center">
            <Box
              as={Clickable}
              onClick={() => {
                if (step > 1) handleBack();
              }}
              style={{ pointerEvents: step === 1 ? 'none' : 'auto', opacity: step === 1 ? 0.5 : 1 }}
            >
              <Button variant="outline" disabled={step === 1}>Back</Button>
            </Box>

            {step < TOTAL_STEPS ? (
              <Box
                as={Clickable}
                onClick={handleNext}
                style={{ pointerEvents: canProceed ? 'auto' : 'none', opacity: canProceed ? 1 : 0.6 }}
              >
                <Button variant="primary" disabled={!canProceed}>Next</Button>
              </Box>
            ) : (
              <Box as={Clickable} onClick={handleSubmit}>
                <Button variant="primary">Submit Survey</Button>
              </Box>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

