/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed

const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

function getPriorityVariant(priority?: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' | 'default' {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  if (priority === 'low') return 'success';
  return 'default';
}

function formatDueDate(value?: string): string {
  if (!value) return '';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleDateString();
}

function makeId(): string {
  return `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasks, setTasks] = useState<Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>>(props.tasks || []);
  const [activeAddColumn, setActiveAddColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<string>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState<string>('');

  useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incomingAction = taskChanged.latest.action;
    const incomingTask = taskChanged.latest.task;
    const incomingId = incomingTask.id || '';
    if (!incomingId) return;

    if (incomingAction === 'delete') {
      setTasks((prev) => prev.filter((task) => (task.id || '') !== incomingId));
      return;
    }

    setTasks((prev) => {
      const exists = prev.some((task) => (task.id || '') === incomingId);
      if (!exists) return [...prev, incomingTask];
      return prev.map((task) => ((task.id || '') === incomingId ? { ...task, ...incomingTask } : task));
    });
  }, [taskChanged.latest]);

  const resolvedColumns = useMemo(() => {
    if (props.columns && props.columns.length > 0) return props.columns;
    return [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' },
    ];
  }, [props.columns]);

  const totalTasks = tasks.length;
  const todoColumnId =
    resolvedColumns.find((col) => (col.name || '').toLowerCase() === 'to do')?.id ||
    resolvedColumns.find((col) => (col.id || '').toLowerCase() === 'todo')?.id ||
    'todo';
  const doneColumnId = resolvedColumns.find((col) => (col.name || '').toLowerCase() === 'done')?.id || 'done';
  const completedCount = tasks.filter((task) => (task.column || '') === doneColumnId).length;

  const moveTask = useCallback(
    (taskId: string, nextColumn: string) => {
      setTasks((prev) => prev.map((task) => ((task.id || '') === taskId ? { ...task, column: nextColumn } : task)));
      taskUpdate({
        action: 'move',
        taskId,
        data: { column: nextColumn },
      });
    },
    [taskUpdate],
  );

  const saveTaskTitle = useCallback(
    (taskId: string) => {
      const trimmed = editingTitle.trim();
      if (!trimmed) return;
      setTasks((prev) => prev.map((task) => ((task.id || '') === taskId ? { ...task, title: trimmed } : task)));
      setEditingTaskId(null);
      setEditingTitle('');
      taskUpdate({
        action: 'edit',
        taskId,
        data: { column: tasks.find((task) => (task.id || '') === taskId)?.column || 'todo' },
      });
    },
    [editingTitle, taskUpdate, tasks],
  );

  const createTask = useCallback(
    () => {
      const trimmed = newTaskTitle.trim();
      if (!trimmed) return;
      const newId = makeId();
      const newTask = {
        id: newId,
        title: trimmed,
        priority: (newTaskPriority as 'low' | 'medium' | 'high') || 'medium',
        assignee: 'NA',
        column: todoColumnId,
        dueDate: '',
      };
      setTasks((prev) => [...prev, newTask]);
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setActiveAddColumn(null);
      taskUpdate({
        action: 'create',
        taskId: newId,
        data: { column: todoColumnId },
      });
    },
    [newTaskPriority, newTaskTitle, taskUpdate, todoColumnId],
  );

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>Task Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Live updates: {taskChanged.all.length} events
              </Text>
            </Stack>
            <Row gap="var(--ggui-spacing-3)">
              <Badge variant="primary" size="md">
                Total: {totalTasks}
              </Badge>
              <Badge variant="success" size="md">
                Completed: {completedCount}
              </Badge>
            </Row>
          </Row>
        </Card>

        {tasks.length === 0 && (
          <Alert variant="info" title="No tasks yet">
            Add your first task in the To Do column.
          </Alert>
        )}

        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
          {resolvedColumns.map((column) => {
            const columnId = column.id || '';
            const columnTasks = tasks.filter((task) => (task.column || '') === columnId);
            return (
              <Card
                key={columnId || column.name}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                style={{
                  background: 'var(--ggui-color-surfaceVariant)',
                  minWidth: '280px',
                  flex: 1,
                }}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                    <Heading level={5}>{column.name || 'Untitled'}</Heading>
                    <Badge variant="default" size="sm">
                      {columnTasks.length}
                    </Badge>
                  </Row>
                  <Divider margin="var(--ggui-spacing-1)" />

                  <Stack gap="var(--ggui-spacing-3)">
                    {columnTasks.map((task) => {
                      const taskId = task.id || '';
                      const isEditing = editingTaskId === taskId;
                      const nextOptions = resolvedColumns
                        .filter((col) => (col.id || '') !== (task.column || ''))
                        .map((col) => ({ value: col.id || '', label: col.name || 'Unknown' }));

                      return (
                        <Card key={taskId} padding="var(--ggui-spacing-3)" shadow="sm" border>
                          <Stack gap="var(--ggui-spacing-2)">
                            <Row justify="between" align="start">
                              <Box style={{ flex: 1 }}>
                                {isEditing ? (
                                  <Input
                                    label="Edit task title"
                                    value={editingTitle}
                                    onChange={setEditingTitle}
                                    placeholder="Task title"
                                  />
                                ) : (
                                  <Button
                                    variant="ghost"
                                    size="sm"
                                    onClick={() => {
                                      setEditingTaskId(taskId);
                                      setEditingTitle(task.title || '');
                                    }}
                                  >
                                    {task.title || 'Untitled task'}
                                  </Button>
                                )}
                              </Box>
                              {isEditing ? (
                                <Row gap="var(--ggui-spacing-2)">
                                  <Button
                                    variant="primary"
                                    size="sm"
                                    onClick={() => {
                                      saveTaskTitle(taskId);
                                    }}
                                  >
                                    Save
                                  </Button>
                                  <Button
                                    variant="ghost"
                                    size="sm"
                                    onClick={() => {
                                      setEditingTaskId(null);
                                      setEditingTitle('');
                                    }}
                                  >
                                    Cancel
                                  </Button>
                                </Row>
                              ) : (
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  onClick={() => {
                                    setEditingTaskId(taskId);
                                    setEditingTitle(task.title || '');
                                  }}
                                >
                                  Edit
                                </Button>
                              )}
                            </Row>

                            <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                              <Badge variant={getPriorityVariant(task.priority)} size="sm">
                                {(task.priority || 'low').toUpperCase()}
                              </Badge>
                              <Avatar name={task.assignee || 'NA'} size="xs" />
                              {task.assignee && (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  {task.assignee}
                                </Text>
                              )}
                              {task.dueDate && (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  Due {formatDueDate(task.dueDate)}
                                </Text>
                              )}
                            </Row>

                            <Select
                              label="Move task"
                              value=""
                              onChange={(value) => {
                                if (value) moveTask(taskId, value);
                              }}
                              placeholder="Move to..."
                              options={nextOptions}
                            />
                          </Stack>
                        </Card>
                      );
                    })}

                    {columnTasks.length === 0 && (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        No tasks in this column.
                      </Text>
                    )}
                  </Stack>

                  {activeAddColumn === columnId ? (
                    <Card padding="var(--ggui-spacing-3)" border>
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          placeholder="Enter task title"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={setNewTaskPriority}
                          options={PRIORITY_OPTIONS}
                        />
                        <Row gap="var(--ggui-spacing-2)">
                          <Button variant="primary" size="sm" onClick={() => createTask()}>
Create
</Button>
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => {
                              setActiveAddColumn(null);
                              setNewTaskTitle('');
                              setNewTaskPriority('medium');
                            }}
                          >
                            Cancel
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button variant="outline" size="sm" fullWidth onClick={() => setActiveAddColumn(columnId)}>
Add Task
</Button>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Stack>
      </Stack>
    </Container>

  );
}

