  'alkali metal': 'var(--ggui-color-error-100)',
  'alkaline earth metal': 'var(--ggui-color-warning-100)',
  'transition metal': 'var(--ggui-color-primary-100)',
  'post-transition metal': 'var(--ggui-color-info-100)',
  metalloid: 'var(--ggui-color-success-100)',
  nonmetal: 'var(--ggui-color-surfaceVariant)',
  halogen: 'var(--ggui-color-warning-100)',
  'noble gas': 'var(--ggui-color-primary-200)',
  lanthanide: 'var(--ggui-color-success-100)',
  actinide: 'var(--ggui-color-error-100)',
};

function normalizeCategory(category?: string): string {
  if (!category) return '';
  return category.toLowerCase().replace(/[-_]+/g, ' ').replace(/\s+/g, ' ').trim();
}

function getCategoryColor(category?: string): string {
  const key = normalizeCategory(category);
  if (!key) return 'var(--ggui-color-surfaceVariant)';
  return CATEGORY_COLORS[key] || 'var(--ggui-color-surfaceVariant)';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    return (props.elements || []).filter((element) => {
      const name = (element.name || '').toLowerCase();
      const symbol = (element.symbol || '').toLowerCase();
      const q = query.toLowerCase().trim();
      if (!q) return true;
      return name.includes(q) || symbol.includes(q);
    });
  }, [props.elements, query]);

  const categories = useMemo(() => {
    const unique = new Set<string>();
    (props.elements || []).forEach((element) => {
      if (element.category) unique.add(element.category);
    });
    return Array.from(unique).sort((a, b) => a.localeCompare(b));
  }, [props.elements]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    return (props.elements || []).find((e) => e.atomicNumber === selectedAtomicNumber) || null;
  }, [props.elements, selectedAtomicNumber]);

  useEffect(() => {
    if (filteredElements.length === 0) {
      setSelectedAtomicNumber(null);
      return;
    }
    if (selectedAtomicNumber === null) return;
    const stillVisible = filteredElements.some((e) => e.atomicNumber === selectedAtomicNumber);
    if (!stillVisible) setSelectedAtomicNumber(null);
  }, [filteredElements, selectedAtomicNumber]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
