              >
                {filteredElements.map((element, index) => {
                  const isSelected = selectedAtomicNumber !== null && selectedAtomicNumber === element.atomicNumber;
                  return (
                    <Card
                      key={`${element.atomicNumber || index}-${element.symbol || 'unknown'}`}
                      as={Clickable}
                      onClick={() => setSelectedAtomicNumber(element.atomicNumber ?? null)}
                      aria-label={`${element.name || 'Unknown element'}, atomic number ${element.atomicNumber ?? 'unknown'}`}
                      role="gridcell"
