                      style={{
                        minHeight: '72px',
                        position: 'relative',
                        gridColumn: element.col || 'auto',
                        gridRow: element.row || 'auto',
                        background: isSelected ? 'var(--ggui-color-container)' : getCategoryColor(element.category),
                        color: isSelected ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)',
                        outline: isSelected ? '2px solid var(--ggui-color-primary-600)' : 'none',
                        outlineOffset: '2px',
                      }}
                    >
                      <Text
                        variant="caption"
                        color={isSelected ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurfaceVariant)'}
                        is="span"
                        style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
                      >
                        {element.atomicNumber ?? '—'}
                      </Text>
                      <Stack align="center" justify="center" style={{ height: '100%' }}>
                        <Text size="xl" weight="bold" align="center">
                          {element.symbol || '—'}
                        </Text>
                      </Stack>
