// Place helper components here if needed
type SpecificationItem = { key: string; value: string };
type ReviewItem = { author: string; rating: number; text: string; date: string };

function toSpecifications(items: unknown[] | undefined): SpecificationItem[] {
  if (!Array.isArray(items)) return [];
  return items
    .map((item, index) => {
      if (item && typeof item === 'object') {
        const record = item as Record<string, unknown>;
        const keyValue = typeof record.key === 'string' ? record.key : `Spec ${index + 1}`;
        const valueValue =
          typeof record.value === 'string' || typeof record.value === 'number'
            ? String(record.value)
            : '';
        return { key: keyValue, value: valueValue };
      }
      return { key: `Spec ${index + 1}`, value: String(item ?? '') };
    })
    .filter((spec) => spec.value.trim().length > 0);
}

function toReviews(items: unknown[] | undefined): ReviewItem[] {
  if (!Array.isArray(items)) return [];
  return items.map((item, index) => {
    if (item && typeof item === 'object') {
      const record = item as Record<string, unknown>;
      return {
        author: typeof record.author === 'string' && record.author ? record.author : `Reviewer ${index + 1}`,
        rating: typeof record.rating === 'number' ? Math.max(0, Math.min(5, Math.round(record.rating))) : 0,
        text: typeof record.text === 'string' ? record.text : '',
        date: typeof record.date === 'string' ? record.date : '',
      };
    }
    return { author: `Reviewer ${index + 1}`, rating: 0, text: String(item ?? ''), date: '' };
  });
}

function formatCurrency(amount: number, currency: string): string {
  const normalizedCurrency = currency || 'USD';
  try {
    return new Intl.NumberFormat(undefined, { style: 'currency', currency: normalizedCurrency }).format(amount);
  } catch {
    const symbol = normalizedCurrency === 'USD' ? '$' : normalizedCurrency === 'EUR' ? '€' : normalizedCurrency === 'GBP' ? '£' : `${normalizedCurrency} `;
    return `${symbol}${amount.toFixed(2)}`;
  }
}

