export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [messageList, setMessageList] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const [draft, setDraft] = useState<string>('');
  const [typingState, setTypingState] = useState<{ sender?: string; active?: boolean } | null>(null);
  const scrollRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setMessageList(props.messages ?? []);
  }, [props.messages]);

  useEffect(() => {
    if (message.latest) {
      setMessageList((prev) => [...prev, message.latest as StreamMessage]);
    }
  }, [message.latest]);

  useEffect(() => {
    if (typing.latest) {
      setTypingState(typing.latest);
    }
  }, [typing.latest]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messageList, typingState]);

  const formatTimestamp = useCallback((value?: string) => {
    if (!value) return '';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return value;
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }, []);

  const groupedMessages = useMemo(() => {
    const safe = Array.isArray(messageList) ? messageList : [];
    return safe.reduce<Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }>>((acc, current) => {
      const last = acc[acc.length - 1];
      if (last && (last.sender ?? '') === (current.sender ?? '')) {
        last.items.push(current);
      } else {
        acc.push({ sender: current.sender, items: [current] });
      }
      return acc;
    }, []);
  }, [messageList]);

  const handleSend = useCallback(() => {
    const trimmed = draft.trim();
    if (!trimmed) return;
    const timestamp = new Date().toISOString();
    sendMessage({ text: trimmed, timestamp });
    setMessageList((prev) => [...prev, { sender: props.currentUser, text: trimmed, timestamp }]);
    setDraft('');
  }, [draft, props.currentUser, sendMessage]);

  const isTypingVisible = Boolean(
    typingState?.active &&
      typingState?.sender &&
      typingState.sender !== props.currentUser
  );

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
