              {props.participantCount} participants
            </Badge>
          </Row>
        </Card>

        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Box
            padding="var(--ggui-spacing-2)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Box
              ref={scrollRef}
              style={{
                height: '50vh',
                overflowY: 'auto',
                padding: 'var(--ggui-spacing-2)',
                background: 'var(--ggui-color-surface)',
              }}
            >
              <Stack gap="var(--ggui-spacing-3)">
                {groupedMessages.length === 0 ? (
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    No messages yet.
                  </Text>
                ) : (
                  groupedMessages.map((group, groupIndex) => {
                    const isCurrentUser = (group.sender ?? '') === props.currentUser;
                    return (
                      <Stack
                        key={`${group.sender ?? 'unknown'}-${groupIndex}`}
                        gap="var(--ggui-spacing-1)"
                        align={isCurrentUser ? 'end' : 'start'}
                      >
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                          {group.sender || 'Unknown'}
                        </Text>
                        {group.items.map((msg, msgIndex) => (
                          <Box
                            key={`${msg.timestamp ?? 't'}-${msgIndex}`}
                            padding="var(--ggui-spacing-3)"
                            background={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-600)'
                                : 'var(--ggui-color-surfaceVariant)'
                            }
                            borderRadius="var(--ggui-shape-radius-md)"
                            style={{ maxWidth: '75%' }}
                          >
                            <Stack gap="var(--ggui-spacing-1)">
                              <Text
                                variant="bodySmall"
                                color={isCurrentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                              >
                                {msg.text || ''}
                              </Text>
                              <Text
                                variant="caption"
                                color={
                                  isCurrentUser
                                    ? 'var(--ggui-color-primary-100)'
                                    : 'var(--ggui-color-onSurfaceVariant)'
                                }
                                align={isCurrentUser ? 'right' : 'left'}
                              >
                                {formatTimestamp(msg.timestamp)}
                              </Text>
                            </Stack>
                          </Box>
                        ))}
                      </Stack>
                    );
                  })
                )}
                {isTypingVisible && (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {typingState?.sender} is typing...
                  </Text>
                )}
              </Stack>
            </Box>
          </Box>
        </Card>

        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                placeholder="Type your message..."
                value={draft}
                onChange={setDraft}
                onKeyDown={(event) => {
                  if (event.key === 'Enter' && !event.shiftKey) {
                    event.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button variant="primary" disabled={!draft.trim()} onClick={handleSend}>
              Send
            </Button>
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}

