                  radius="lg"
                  border
                  style={{ borderColor }}
                >
                  <Box
                    padding="var(--ggui-spacing-2)"
                    background={flashActive ? flashColor : 'var(--ggui-color-surfaceVariant)'}
                    borderRadius="var(--ggui-shape-radius-md)"
                  >
                    <Stack gap="var(--ggui-spacing-3)">
                      <Row justify="between" align="start">
                        <Stack gap="var(--ggui-spacing-1)">
                          <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
                            {stock.symbol ?? 'N/A'}
                          </Text>
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                            {stock.name ?? 'Unknown Company'}
                          </Text>
                        </Stack>
                        <Badge variant={isPositive ? 'success' : 'error'}>
                          {isPositive ? 'Up' : 'Down'}
                        </Badge>
                      </Row>

                      <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface)">
                        ${formatPrice(stock.price)}
                      </Text>

                      <Row justify="between" align="center">
                        <Text weight="semibold" color={changeColor}>
                          {formatSigned(stock.change)}
                        </Text>
                        <Row gap="var(--ggui-spacing-1)" align="center">
                          <Text color={changeColor} weight="semibold" aria-hidden="true">
                            {isPositive ? '▲' : '▼'}
                          </Text>
                          <Text color={changeColor} weight="semibold" aria-label={`${stock.symbol ?? 'Stock'} ${isPositive ? 'up' : 'down'} ${formatPercent(stock.changePercent)}`}>
                            {formatPercent(stock.changePercent)}
                          </Text>
                        </Row>
                      </Row>

                      <Box
                        padding="var(--ggui-spacing-1)"
                        borderRadius="var(--ggui-shape-radius-sm)"
                        background="var(--ggui-color-surface)"
                      >
                        <Text variant="caption" color={borderColor} aria-live="polite">
                          Live updates enabled for {stock.symbol ?? 'N/A'} at ${formatPrice(stock.price)} ({isPositive ? 'up' : 'down'} {formatPercent(stock.changePercent)})
                        </Text>
                      </Box>
                    </Stack>
                  </Box>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Place helper components here if needed
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const DEFAULT_AVATARS = ['😀', '🚀', '🎨', '🧠'];

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar ?? '');
  const [role, setRole] = useState(props.initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme === 'dark' ? 'dark' : 'light');
  const [showSubmitted, setShowSubmitted] = useState(false);

  const avatars = useMemo(() => {
    if (props.avatarOptions && props.avatarOptions.length > 0) return props.avatarOptions.slice(0, 4);
    return DEFAULT_AVATARS;
  }, [props.avatarOptions]);

  const roles = useMemo(() => {
    if (props.roleOptions && props.roleOptions.length > 0) return props.roleOptions;
    return ['Developer', 'Designer', 'Manager', 'Other'];
  }, [props.roleOptions]);

  useEffect(() => {
    if (!avatar && avatars.length > 0) {
      setAvatar(avatars[0]);
    }
  }, [avatar, avatars]);

  const emailError = useMemo(() => {
    if (!email.trim()) return 'Email is required';
    if (!EMAIL_REGEX.test(email.trim())) return 'Please enter a valid email address';
    return '';
  }, [email]);

  const nameError = useMemo(() => {
    if (!name.trim()) return 'Name is required';
    return '';
  }, [name]);

  const stepOneValid = useMemo(() => {
    return name.trim().length > 0 && EMAIL_REGEX.test(email.trim()) && avatar.trim().length > 0;
  }, [name, email, avatar]);

  const stepTwoValid = useMemo(() => {
    return role.trim().length > 0 && (theme === 'light' || theme === 'dark');
  }, [role, theme]);

  const canProceed = step === 1 ? stepOneValid : step === 2 ? stepTwoValid : true;
  const progressValue = (step / 3) * 100;

  const handleNext = useCallback(() => {
    if (!canProceed) return;
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [canProceed]);

  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleComplete = useCallback(() => {
    if (!stepOneValid || !stepTwoValid) return;
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    complete(payload);
    setShowSubmitted(true);
  }, [stepOneValid, stepTwoValid, name, email, avatar, role, emailNotifications, theme, complete]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" variant="default" showLabel />
            <Row gap="var(--ggui-spacing-2)" wrap>
              <Badge variant={step >= 1 ? 'primary' : 'default'}>1. Profile</Badge>
              <Badge variant={step >= 2 ? 'primary' : 'default'}>2. Preferences</Badge>
              <Badge variant={step >= 3 ? 'primary' : 'default'}>3. Review</Badge>
            </Row>
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          border
          shadow="md"
        >
          <Box
            key={step}
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
              transition: 'all 200ms ease-in-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your full name"
                  required
                  error={nameError || undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="you@example.com"
                  required
                  error={email && emailError ? emailError : undefined}
                  helperText={!email ? 'We will use this for account updates' : undefined}
                />

                <Stack gap="var(--ggui-spacing-2)">
                  <Text id="avatar-group-label" variant="label" color="var(--ggui-color-onSurfaceVariant)">Choose Avatar</Text>
                  <Row
                    gap="var(--ggui-spacing-3)"
                    wrap
                    wrap
                  >
                    {avatars.map((emoji, index) => (
                      <Card
                        key={emoji}
                        as={Clickable}
                        role="radio"
                        aria-checked={avatar === emoji}
                        tabIndex={avatar === emoji ? 0 : -1}
                        onClick={() => setAvatar(emoji)}
                        onKeyDown={(event) => {
                          if (event.key === 'Enter' || event.key === ' ') {
                            event.preventDefault();
                            setAvatar(emoji);
                            return;
                          }
                          if (event.key === 'ArrowRight' || event.key === 'ArrowDown') {
                            event.preventDefault();
                            const nextIndex = (index + 1) % avatars.length;
                            setAvatar(avatars[nextIndex]);
                            return;
                          }
                          if (event.key === 'ArrowLeft' || event.key === 'ArrowUp') {
                            event.preventDefault();
                            const prevIndex = (index - 1 + avatars.length) % avatars.length;
                            setAvatar(avatars[prevIndex]);
                          }
                        }}
                        padding="var(--ggui-spacing-3)"
                        border
                        radius="md"
                        shadow="none"
                        style={{
                          borderColor: avatar === emoji ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                          background: avatar === emoji ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                          minWidth: '56px',
                          textAlign: 'center',
                        }}
                      >
                        <Text size="2xl" align="center">{emoji}</Text>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  required
                  options={roles.map((r) => ({ value: r, label: r }))}
                  error={!role ? 'Role is required' : undefined}
                />
                <Toggle
                  label="Enable email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label={theme === 'dark' ? 'Theme: Dark' : 'Theme: Light'}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Alert variant="info" title="Please confirm your details">
                  You can go back to edit anything before completing setup.
                </Alert>
                <Card padding="var(--ggui-spacing-4)" border shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                    <Row justify="between" align="center"><Text variant="label">Avatar</Text><Text size="xl">{avatar || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
                {showSubmitted && (
                  <Alert variant="success" title="Setup completed">Your onboarding details were submitted successfully.</Alert>
                )}
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-4)" />

          <Row justify="between" align="center">
            <Button variant="outline" onClick={handleBack} disabled={step === 1}>
              Back
            </Button>
            {step < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={!canProceed}>
                Next
              </Button>
            ) : (
              <Row gap="var(--ggui-spacing-2)">
                <Button variant="outline" onClick={handleBack}>Go Back</Button>
                <Button variant="primary" onClick={handleComplete} disabled={!stepOneValid || !stepTwoValid}>
                  Complete Setup
                </Button>
              </Row>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
